import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Test

class SpacingAroundRangeUntilOperatorRuleTest {
    private val spacingAroundRangeOperatorRuleAssertThat = assertThatRule { SpacingAroundRangeOperatorRule() }

    @Test
    fun `Given a range-until operator with various spacing`() {
        val code =
            """
            @OptIn(ExperimentalStdlibApi::class)
            fun foo(int: Int): String =
                when (int) {
                    in 10..<20 -> "A"
                    in 20..< 30 -> "B"
                    in 30 ..< 40 -> "C"
                    in 40 ..<50 -> "D"
                    else -> "unknown"
                }
            """.trimIndent()
        val formattedCode =
            """
            @OptIn(ExperimentalStdlibApi::class)
            fun foo(int: Int): String =
                when (int) {
                    in 10..<20 -> "A"
                    in 20..<30 -> "B"
                    in 30..<40 -> "C"
                    in 40..<50 -> "D"
                    else -> "unknown"
                }
            """.trimIndent()
        spacingAroundRangeOperatorRuleAssertThat(code)
            .hasLintViolations(
                LintViolation(5, 18, "Unexpected spacing after \"..<\""),
                LintViolation(6, 17, "Unexpected spacing around \"..<\""),
                LintViolation(7, 16, "Unexpected spacing before \"..<\""),
            ).isFormattedAs(formattedCode)
    }

    @Test
    fun `Given a range-until operator in a for loop`() {
        val code =
            """
            @OptIn(ExperimentalStdlibApi::class)
            fun foo() {
                for (i in 1..<4) print(i)
                for (i in 1..< 4) print(i)
                for (i in 1 ..< 4) print(i)
                for (i in 1 ..<4) print(i)
            }
            """.trimIndent()
        val formattedCode =
            """
            @OptIn(ExperimentalStdlibApi::class)
            fun foo() {
                for (i in 1..<4) print(i)
                for (i in 1..<4) print(i)
                for (i in 1..<4) print(i)
                for (i in 1..<4) print(i)
            }
            """.trimIndent()
        spacingAroundRangeOperatorRuleAssertThat(code)
            .hasLintViolations(
                LintViolation(4, 18, "Unexpected spacing after \"..<\""),
                LintViolation(5, 17, "Unexpected spacing around \"..<\""),
                LintViolation(6, 16, "Unexpected spacing before \"..<\""),
            ).isFormattedAs(formattedCode)
    }

    @Test
    fun `Given a range-until operator without spacing`() {
        val code =
            """
            @OptIn(ExperimentalStdlibApi::class)
            fun foo() {
                for (i in 1..<10) print(i)
                val range = 5..<15
            }
            """.trimIndent()
        spacingAroundRangeOperatorRuleAssertThat(code)
            .hasNoLintViolations()
    }
}
"}

