{"file_path": "/project/VerifyRangeUntilFix.kt", "content": "import com.pinterest.ktlint.rule.engine.api.Code
import com.pinterest.ktlint.rule.engine.api.KtLintRuleEngine
import com.pinterest.ktlint.ruleset.standard.rules.SpacingAroundRangeOperatorRule

fun main() {
    val code = """
        @OptIn(ExperimentalStdlibApi::class)
        fun foo(int: Int): String =
            when (int) {
                in 10..<20 -> "A"
                in 20..< 30 -> "B"
                in 30 ..< 40 -> "C"
                in 40 ..<50 -> "D"
                else -> "unknown"
            }
    """.trimIndent()

    val ruleEngine = KtLintRuleEngine(
        ruleProviders = setOf(
            { SpacingAroundRangeOperatorRule() }
        )
    )

    val lintErrors = mutableListOf<String>()
    ruleEngine.lint(Code.fromSnippet(code)) { lintError ->
        lintErrors.add("Line ${lintError.line}, Column ${lintError.col}: ${lintError.detail}")
    }

    println("Found ${lintErrors.size} lint errors:")
    lintErrors.forEach { println("  - $it") }

    // Test auto-correction
    val formattedCode = ruleEngine.format(Code.fromSnippet(code)) { _ -> }
    println("\nFormatted code:")
    println(formattedCode)
}
"}

